import{_ as t,o as n,c as o,ag as a}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Connection Status","description":"","frontmatter":{},"headers":[],"relativePath":"user/connection-status.md","filePath":"user/connection-status.md","lastUpdated":1775719799000}'),s={name:"user/connection-status.md"};function i(r,e,c,l,d,h){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="connection-status" tabindex="-1">Connection Status <a class="header-anchor" href="#connection-status" aria-label="Permalink to &quot;Connection Status&quot;">​</a></h1><p>RustChat keeps you informed about your connection status to ensure you always know when your messages are being sent and received in real-time.</p><h2 id="connection-states" tabindex="-1">Connection States <a class="header-anchor" href="#connection-states" aria-label="Permalink to &quot;Connection States&quot;">​</a></h2><h3 id="🟢-connected" tabindex="-1">🟢 Connected <a class="header-anchor" href="#🟢-connected" aria-label="Permalink to &quot;🟢 Connected&quot;">​</a></h3><p>When you see a <strong>green dot</strong> in the header, you&#39;re fully connected and all messages are being sent and received in real-time.</p><hr><h3 id="🟡-reconnecting" tabindex="-1">🟡 Reconnecting <a class="header-anchor" href="#🟡-reconnecting" aria-label="Permalink to &quot;🟡 Reconnecting&quot;">​</a></h3><p>If your connection is interrupted, you&#39;ll see a <strong>yellow banner</strong> at the top of the screen:</p><blockquote><p><strong>Reconnecting...</strong></p></blockquote><p><strong>What this means:</strong></p><ul><li>Your connection was temporarily lost (usually due to network changes or brief interruptions)</li><li>RustChat is automatically trying to reconnect</li><li>You can still read existing messages</li></ul><p><strong>What happens:</strong></p><ul><li>The screen content is slightly dimmed (80% opacity)</li><li>The message composer is disabled</li><li>Reconnection happens automatically within a few seconds</li></ul><p><strong>No action needed</strong> - just wait a moment and you&#39;ll be reconnected automatically.</p><hr><h3 id="🟠-connection-lost" tabindex="-1">🟠 Connection Lost <a class="header-anchor" href="#🟠-connection-lost" aria-label="Permalink to &quot;🟠 Connection Lost&quot;">​</a></h3><p>If reconnection fails for more than 5 seconds, the banner turns <strong>orange</strong>:</p><blockquote><p><strong>Connection lost. Retrying in X seconds...</strong></p></blockquote><p><strong>What this means:</strong></p><ul><li>The automatic reconnection is taking longer than expected</li><li>Your conversation may be out of date</li><li>New messages from others won&#39;t appear until reconnected</li></ul><p><strong>What you can do:</strong></p><ul><li>Wait for the automatic retry</li><li>Click <strong>&quot;Retry now&quot;</strong> to force an immediate reconnection attempt</li><li>Continue reading existing messages (content is dimmed to 60%)</li></ul><hr><h3 id="🔌-disconnected" tabindex="-1">🔌 Disconnected <a class="header-anchor" href="#🔌-disconnected" aria-label="Permalink to &quot;🔌 Disconnected&quot;">​</a></h3><p>If your connection can&#39;t be restored after 30 seconds, a <strong>full-screen modal</strong> appears:</p><blockquote><p><strong>Disconnected</strong><br> You&#39;ve been disconnected from the server. Your conversation may be out of date.</p></blockquote><p><strong>You have two options:</strong></p><ol><li><strong>Reconnect</strong> - Attempts to restore your connection and sync any missed messages</li><li><strong>Refresh page</strong> - Reloads the entire application (use this if reconnect doesn&#39;t work)</li></ol><p><strong>Why this happens:</strong></p><ul><li>Your device went to sleep for an extended period</li><li>Network connection was lost (WiFi turned off, switching networks)</li><li>The server was restarted</li><li>Browser tab was in the background for a long time</li></ul><hr><h2 id="common-questions" tabindex="-1">Common Questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common Questions&quot;">​</a></h2><h3 id="will-i-lose-my-messages-if-i-get-disconnected" tabindex="-1">Will I lose my messages if I get disconnected? <a class="header-anchor" href="#will-i-lose-my-messages-if-i-get-disconnected" aria-label="Permalink to &quot;Will I lose my messages if I get disconnected?&quot;">​</a></h3><p><strong>No.</strong> Messages you sent before disconnection are already delivered. Messages others sent while you were disconnected will appear once you reconnect.</p><h3 id="what-happens-to-messages-i-type-while-disconnected" tabindex="-1">What happens to messages I type while disconnected? <a class="header-anchor" href="#what-happens-to-messages-i-type-while-disconnected" aria-label="Permalink to &quot;What happens to messages I type while disconnected?&quot;">​</a></h3><p>The message composer is disabled during disconnection to prevent messages from failing to send. Once reconnected, you can type and send normally.</p><h3 id="why-does-the-content-get-dimmed" tabindex="-1">Why does the content get dimmed? <a class="header-anchor" href="#why-does-the-content-get-dimmed" aria-label="Permalink to &quot;Why does the content get dimmed?&quot;">​</a></h3><p>The dimming (80% → 60% → blur) is a visual cue that the content might be stale. Messages may have been edited or deleted while you were disconnected.</p><h3 id="how-do-i-know-if-i-missed-any-messages" tabindex="-1">How do I know if I missed any messages? <a class="header-anchor" href="#how-do-i-know-if-i-missed-any-messages" aria-label="Permalink to &quot;How do I know if I missed any messages?&quot;">​</a></h3><p>When you reconnect:</p><ol><li>Missed messages will automatically appear in the conversation</li><li>Unread message badges will update</li><li>The connection indicator will turn green again</li></ol><h3 id="can-i-prevent-disconnections" tabindex="-1">Can I prevent disconnections? <a class="header-anchor" href="#can-i-prevent-disconnections" aria-label="Permalink to &quot;Can I prevent disconnections?&quot;">​</a></h3><p>Most disconnections are caused by:</p><ul><li><strong>Network changes</strong> (switching WiFi, moving between cell towers)</li><li><strong>Device sleep</strong> (laptop lid closed, phone screen off)</li><li><strong>Browser throttling</strong> (tab in background for extended time)</li></ul><p>These are normal and RustChat handles them gracefully. Just keep an eye on the connection indicator!</p><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="stuck-on-reconnecting-for-a-long-time" tabindex="-1">Stuck on &quot;Reconnecting...&quot; for a long time <a class="header-anchor" href="#stuck-on-reconnecting-for-a-long-time" aria-label="Permalink to &quot;Stuck on &quot;Reconnecting...&quot; for a long time&quot;">​</a></h3><ol><li>Check your internet connection</li><li>Try clicking <strong>&quot;Retry now&quot;</strong></li><li>If still stuck, click <strong>&quot;Refresh page&quot;</strong> in the disconnect modal</li></ol><h3 id="keep-getting-disconnected-frequently" tabindex="-1">Keep getting disconnected frequently <a class="header-anchor" href="#keep-getting-disconnected-frequently" aria-label="Permalink to &quot;Keep getting disconnected frequently&quot;">​</a></h3><ol><li>Check if your WiFi is stable</li><li>Disable VPN temporarily to test</li><li>Check if browser extensions are interfering</li><li>Try a different browser</li></ol><h3 id="reconnect-doesn-t-work-but-refresh-does" tabindex="-1">Reconnect doesn&#39;t work but refresh does <a class="header-anchor" href="#reconnect-doesn-t-work-but-refresh-does" aria-label="Permalink to &quot;Reconnect doesn&#39;t work but refresh does&quot;">​</a></h3><p>This usually means your authentication session expired. Refreshing the page re-authenticates you. This is normal after very long periods of inactivity.</p><hr><h2 id="privacy-note" tabindex="-1">Privacy Note <a class="header-anchor" href="#privacy-note" aria-label="Permalink to &quot;Privacy Note&quot;">​</a></h2><p>The connection status indicator only reflects your local network connection to the RustChat server. It doesn&#39;t track or report your online status to other users.</p>',56)])])}const p=t(s,[["render",i]]);export{g as __pageData,p as default};
